async function HandleOnLoadEvent(e){var t="https://worker-winter-glade-cd02.bigtentgames.workers.dev/"+encodeURIComponent(window.location.search.split("?")[1]);await fetch(t,{headers:{Host:window.location.hostname}}).then((e=>{if(!e.ok)throw new Error("Server error: "+e.status);return e.text()})).then((e=>{})).catch((e=>{}))}window.addEventListener("load",HandleOnLoadEvent);